css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #38bdf8;
  width: 50px;
  aspect-ratio: 1;
  color: var(--loader-color, #2563eb);
  border: 2px solid;
  box-sizing: border-box;
  background:radial-gradient(farthest-side,currentColor 90%,#0000),radial-gradient(farthest-side,#0000 90%,currentColor);
  background-size: 16px 16px;
  background-position: 0 0;
  animation: l8 2s infinite;
}@keyframes l8{100% {background-position: 0px 32px,-16px 0}}
